import {{ Injectable }} from '@nestjs/common';
import {{ OrderService }} from './models/order.model';
import {{ OrderServiceRepository }} from './repositories/order.repository';

@Injectable()
export class OrderServiceService {{
  constructor(
    private readonly repository: OrderServiceRepository,
  ) {{}}

  async findAll(): Promise<OrderService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<OrderService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<OrderService>): Promise<OrderService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<OrderService>): Promise<OrderService> {{
    return this.repository.update(id, data);
  }}
}}

